export * from './types';

import { randomUUID } from 'node:crypto';

import type { AutomationFailureSpanInput, ObservabilityClient } from './types';
import type { ObservabilityConfig, TraceContext } from './types';

interface LogEntry {
  level: 'debug' | 'info' | 'warn' | 'error';
  message: string;
  serviceName: string;
  environment: string;
  timestamp: string;
  meta?: Record<string, unknown>;
}

function normalizeConfig(config?: Partial<ObservabilityConfig>): ObservabilityConfig {
  const serviceName = config?.serviceName?.trim();
  const environment = config?.environment?.trim();
  if (!serviceName) {
    throw new Error('observability config requires serviceName');
  }
  if (!environment) {
    throw new Error('observability config requires environment');
  }

  return {
    serviceName,
    environment,
    ...(config?.endpoint?.trim() ? { endpoint: config.endpoint.trim() } : {}),
  };
}

function createTraceId(): string {
  return randomUUID().replace(/-/g, '');
}

function createSpanId(): string {
  return randomUUID().replace(/-/g, '').slice(0, 16);
}

function shouldLogToStdout(level: LogEntry['level']): boolean {
  const configured = (process.env.LIFEOS_OBSERVABILITY_STDOUT ?? 'true').trim().toLowerCase();
  if (configured === 'false' || configured === '0') {
    return level === 'error' || level === 'warn';
  }
  return true;
}

function writeLog(entry: LogEntry): void {
  if (!shouldLogToStdout(entry.level)) {
    return;
  }

  const serialized = JSON.stringify(entry);
  if (entry.level === 'error' || entry.level === 'warn') {
    process.stderr.write(`${serialized}\n`);
    return;
  }
  process.stdout.write(`${serialized}\n`);
}

export function createObservabilityClient(config?: ObservabilityConfig): ObservabilityClient {
  const resolved = normalizeConfig(config);
  const spanStartTimes = new Map<string, number>();

  return {
    startSpan(name: string, context?: TraceContext): TraceContext {
      const span = {
        traceId: context?.traceId ?? createTraceId(),
        spanId: createSpanId(),
        ...(context?.spanId ? { parentSpanId: context.spanId } : {}),
      };

      spanStartTimes.set(span.spanId, Date.now());
      writeLog({
        level: 'debug',
        message: `span.start:${name}`,
        serviceName: resolved.serviceName,
        environment: resolved.environment,
        timestamp: new Date().toISOString(),
        meta: {
          traceId: span.traceId,
          spanId: span.spanId,
          parentSpanId: span.parentSpanId,
        },
      });

      return span;
    },

    endSpan(context: TraceContext): void {
      const startedAt = spanStartTimes.get(context.spanId);
      spanStartTimes.delete(context.spanId);
      const durationMs = startedAt ? Date.now() - startedAt : undefined;

      writeLog({
        level: 'debug',
        message: 'span.end',
        serviceName: resolved.serviceName,
        environment: resolved.environment,
        timestamp: new Date().toISOString(),
        meta: {
          traceId: context.traceId,
          spanId: context.spanId,
          ...(context.parentSpanId ? { parentSpanId: context.parentSpanId } : {}),
          ...(durationMs !== undefined ? { durationMs } : {}),
        },
      });
    },

    recordMetric(name: string, value: number, tags?: Record<string, string>): void {
      writeLog({
        level: 'info',
        message: `metric:${name}`,
        serviceName: resolved.serviceName,
        environment: resolved.environment,
        timestamp: new Date().toISOString(),
        meta: {
          value,
          ...(tags ? { tags } : {}),
        },
      });
    },

    log(
      level: 'debug' | 'info' | 'warn' | 'error',
      message: string,
      meta?: Record<string, unknown>,
    ): void {
      writeLog({
        level,
        message,
        serviceName: resolved.serviceName,
        environment: resolved.environment,
        timestamp: new Date().toISOString(),
        ...(meta ? { meta } : {}),
      });
    },
  };
}

export function emitAutomationFailureSpan(
  client: ObservabilityClient,
  spanName: string,
  input: AutomationFailureSpanInput,
): TraceContext {
  const span = client.startSpan(spanName);
  client.log('error', `automation.failure:${input.errorCode}`, {
    traceId: span.traceId,
    spanId: span.spanId,
    parentSpanId: span.parentSpanId,
    household_id: input.householdId,
    actor_id: input.actorId,
    action_type: input.actionType,
    error_code: input.errorCode,
    fix_suggestion: input.fixSuggestion,
    ...(input.objectId ? { object_id: input.objectId } : {}),
    ...(input.objectRef ? { object_ref: input.objectRef } : {}),
    ...(input.details ? input.details : {}),
  });
  client.endSpan(span);
  return span;
}

export interface TraceContext {
  traceId: string;
  spanId: string;
  parentSpanId?: string;
}

export interface ObservabilityConfig {
  serviceName: string;
  environment: string;
  endpoint?: string;
}

export interface AutomationFailureSpanInput {
  householdId: string;
  actorId: string;
  actionType: string;
  errorCode: string;
  fixSuggestion: string;
  objectId?: string;
  objectRef?: string;
  details?: Record<string, unknown>;
}

export interface ObservabilityClient {
  startSpan(name: string, context?: TraceContext): TraceContext;
  endSpan(context: TraceContext): void;
  recordMetric(name: string, value: number, tags?: Record<string, string>): void;
  log(
    level: 'debug' | 'info' | 'warn' | 'error',
    message: string,
    meta?: Record<string, unknown>,
  ): void;
}

import { getNextDueDate } from './recurrence';

export interface ChoreRunInput {
  completed_at: string;
}

export function calculateStreak(
  runs: ChoreRunInput[],
  recurrenceRule: string | null,
  now: Date = new Date(),
): number {
  void now;

  if (runs.length === 0) {
    return 0;
  }

  if (!recurrenceRule) {
    return runs.length;
  }

  let streak = 1;

  for (let index = 0; index < runs.length - 1; index += 1) {
    const newerRun = runs[index];
    const olderRun = runs[index + 1];
    if (!newerRun || !olderRun) {
      return 0;
    }

    const newerCompletedAt = new Date(newerRun.completed_at);
    const olderCompletedAt = new Date(olderRun.completed_at);

    if (Number.isNaN(newerCompletedAt.getTime()) || Number.isNaN(olderCompletedAt.getTime())) {
      return 0;
    }

    const expectedNext = getNextDueDate(recurrenceRule, olderCompletedAt);
    if (!expectedNext) {
      return 0;
    }

    const allowedIntervalMs = expectedNext.getTime() - olderCompletedAt.getTime();
    if (allowedIntervalMs <= 0) {
      return 0;
    }

    const actualIntervalMs = newerCompletedAt.getTime() - olderCompletedAt.getTime();
    if (actualIntervalMs > allowedIntervalMs) {
      return 0;
    }

    streak += 1;
  }

  return streak;
}

const DAY_TO_UTC_INDEX: Record<string, number> = {
  SU: 0,
  MO: 1,
  TU: 2,
  WE: 3,
  TH: 4,
  FR: 5,
  SA: 6,
};

type ParsedRRule = {
  freq: 'DAILY' | 'WEEKLY' | 'MONTHLY';
  byDay: number[];
  until: Date | null;
};

function parseDateValue(value: string): Date | null {
  const raw = value.trim();

  if (/^\d{8}$/.test(raw)) {
    const year = Number(raw.slice(0, 4));
    const month = Number(raw.slice(4, 6)) - 1;
    const day = Number(raw.slice(6, 8));
    return new Date(Date.UTC(year, month, day, 23, 59, 59, 999));
  }

  if (/^\d{8}T\d{6}Z$/.test(raw)) {
    const year = Number(raw.slice(0, 4));
    const month = Number(raw.slice(4, 6)) - 1;
    const day = Number(raw.slice(6, 8));
    const hour = Number(raw.slice(9, 11));
    const minute = Number(raw.slice(11, 13));
    const second = Number(raw.slice(13, 15));
    return new Date(Date.UTC(year, month, day, hour, minute, second));
  }

  const isoDate = new Date(raw);
  return Number.isNaN(isoDate.getTime()) ? null : isoDate;
}

function parseRRule(rrule: string): ParsedRRule {
  const parts = rrule
    .split(';')
    .map((segment) => segment.trim())
    .filter((segment) => segment.length > 0);

  const options = new Map<string, string>();
  for (const part of parts) {
    const [rawKey, rawValue] = part.split('=', 2);
    if (!rawKey || !rawValue) {
      continue;
    }
    options.set(rawKey.toUpperCase(), rawValue.toUpperCase());
  }

  const freqValue = options.get('FREQ');
  if (!freqValue || (freqValue !== 'DAILY' && freqValue !== 'WEEKLY' && freqValue !== 'MONTHLY')) {
    throw new Error(`Unsupported recurrence frequency: ${freqValue ?? 'missing'}`);
  }

  const byDay = (options.get('BYDAY') ?? '')
    .split(',')
    .map((token) => token.trim())
    .filter((token) => token.length > 0)
    .map((token) => DAY_TO_UTC_INDEX[token])
    .filter((day): day is number => typeof day === 'number' && Number.isInteger(day));

  const untilRaw = options.get('UNTIL');
  const until = untilRaw ? parseDateValue(untilRaw) : null;

  return {
    freq: freqValue,
    byDay,
    until,
  };
}

function addUtcDays(fromDate: Date, days: number): Date {
  const result = new Date(fromDate);
  result.setUTCDate(result.getUTCDate() + days);
  return result;
}

function addUtcMonthsClamped(fromDate: Date, months: number): Date {
  const year = fromDate.getUTCFullYear();
  const month = fromDate.getUTCMonth();
  const day = fromDate.getUTCDate();

  const targetMonth = month + months;
  const targetYear = year + Math.floor(targetMonth / 12);
  const normalizedMonth = ((targetMonth % 12) + 12) % 12;
  const lastDayOfTargetMonth = new Date(Date.UTC(targetYear, normalizedMonth + 1, 0)).getUTCDate();

  const result = new Date(fromDate);
  result.setUTCFullYear(targetYear, normalizedMonth, Math.min(day, lastDayOfTargetMonth));
  return result;
}

function matchesByDay(date: Date, allowedDays: number[]): boolean {
  if (allowedDays.length === 0) {
    return true;
  }

  return allowedDays.includes(date.getUTCDay());
}

function advanceToNextAllowedDay(fromDate: Date, allowedDays: number[]): Date {
  let cursor = addUtcDays(fromDate, 1);
  for (let index = 0; index < 370; index += 1) {
    if (matchesByDay(cursor, allowedDays)) {
      return cursor;
    }
    cursor = addUtcDays(cursor, 1);
  }

  throw new Error('Unable to compute next allowed BYDAY occurrence');
}

export function getNextDueDate(rrule: string, fromDate: Date): Date | null {
  const parsed = parseRRule(rrule);

  if (parsed.until && fromDate.getTime() > parsed.until.getTime()) {
    return null;
  }

  let nextDate: Date;
  if (parsed.freq === 'DAILY') {
    nextDate = parsed.byDay.length > 0 ? advanceToNextAllowedDay(fromDate, parsed.byDay) : addUtcDays(fromDate, 1);
  } else if (parsed.freq === 'WEEKLY') {
    if (parsed.byDay.length === 0) {
      nextDate = addUtcDays(fromDate, 7);
    } else {
      nextDate = advanceToNextAllowedDay(fromDate, parsed.byDay);
    }
  } else {
    nextDate = addUtcMonthsClamped(fromDate, 1);
    if (parsed.byDay.length > 0 && !matchesByDay(nextDate, parsed.byDay)) {
      nextDate = advanceToNextAllowedDay(nextDate, parsed.byDay);
    }
  }

  if (parsed.until && nextDate.getTime() > parsed.until.getTime()) {
    return null;
  }

  return nextDate;
}

export function isOverdue(dueAt: string, now: Date = new Date()): boolean {
  const dueDate = new Date(dueAt);
  if (Number.isNaN(dueDate.getTime())) {
    return false;
  }

  return dueDate.getTime() < now.getTime();
}

