    household_id: row.household_id,
    kind: row.kind,
    trust_level: row.trust_level,
    capabilities: parseJson<SurfaceCapability[]>(row.capabilities_json, []),
    registered_at: row.registered_at,
  });
}

export class HomeNodeGraphClient {
  private readonly db: Database.Database;

  constructor(dbPath: string = process.env.LIFEOS_HOME_NODE_DB_PATH ?? '') {
    if (!dbPath || dbPath.trim().length === 0) {
      throw new Error('HomeNodeGraphClient requires a valid dbPath');
    }

    mkdirSync(dirname(dbPath), { recursive: true });
    this.db = new Database(dbPath);
    this.db.pragma('journal_mode = WAL');
    this.db.pragma('foreign_keys = ON');
  }

  initializeSchema(): void {
    this.db.exec(migration001Sql);
    this.db.exec(migration002Sql);
    this.db.exec(migration003Sql);
    this.db.exec(migration004Sql);
    this.ensureFeatureSchema();
  }

  private ensureFeatureSchema(): void {
    this.ensureColumn('home_state_snapshots', 'updated_at', "TEXT DEFAULT ''");
    this.db.exec(
      'CREATE UNIQUE INDEX IF NOT EXISTS idx_home_state_snapshots_household_id ON home_state_snapshots(household_id)',
    );
  }

  private ensureColumn(tableName: string, columnName: string, definition: string): void {
    const columns = this.db.prepare(`PRAGMA table_info(${tableName})`).all() as Array<{
      name: string;
    }>;
    if (columns.some((column) => column.name === columnName)) {
      return;
    }

    this.db.exec(`ALTER TABLE ${tableName} ADD COLUMN ${columnName} ${definition}`);
  }

  upsertHome(input: HomeNodeHomeWrite): HomeNodeHome {
    const createdAt = ensureIsoDateTime(input.createdAt ?? new Date().toISOString());

    this.db
      .prepare(
        `INSERT INTO homes (
          home_id,
          household_id,
          name,
          timezone,
          quiet_hours_start,
          quiet_hours_end,
          routine_profile,
          created_at
        ) VALUES (
          @home_id,
          @household_id,
          @name,
          @timezone,
          @quiet_hours_start,
          @quiet_hours_end,
          @routine_profile,
          @created_at
        )
        ON CONFLICT(home_id) DO UPDATE SET
          household_id = excluded.household_id,
          name = excluded.name,
          timezone = excluded.timezone,
          quiet_hours_start = excluded.quiet_hours_start,
          quiet_hours_end = excluded.quiet_hours_end,
          routine_profile = excluded.routine_profile`,
      )
      .run({
        home_id: input.homeId,
        household_id: input.householdId,
        name: input.name,
        timezone: input.timezone,
        quiet_hours_start: input.quietHoursStart ?? null,
        quiet_hours_end: input.quietHoursEnd ?? null,
        routine_profile: input.routineProfile ?? null,
        created_at: createdAt,
      });

    const home = this.getHomeById(input.homeId);
    if (!home) {
      throw new Error(`Failed to upsert home ${input.homeId}`);
    }

    return home;
  }

  getHomeById(homeId: string): HomeNodeHome | null {
    const row = this.db.prepare('SELECT * FROM homes WHERE home_id = ? LIMIT 1').get(homeId) as
      | HomeNodeHomeRow
      | undefined;

    if (!row) {
      return null;
    }

    return toHomeNodeHome(row);
  }

  getHomeByHouseholdId(householdId: string): HomeNodeHome | null {
    const row = this.db
      .prepare('SELECT * FROM homes WHERE household_id = ? LIMIT 1')
      .get(householdId) as HomeNodeHomeRow | undefined;

    if (!row) {
      return null;
    }

    return toHomeNodeHome(row);
  }

  upsertZone(input: HomeNodeZoneWrite): HomeNodeZone {
    const createdAt = ensureIsoDateTime(input.createdAt ?? new Date().toISOString());

    this.db
      .prepare(
        `INSERT INTO zones (
          zone_id,
          home_id,
          name,
          type,
          created_at
        ) VALUES (
          @zone_id,
          @home_id,
          @name,
          @type,
          @created_at
        )
        ON CONFLICT(zone_id) DO UPDATE SET
          home_id = excluded.home_id,
          name = excluded.name,
          type = excluded.type`,
      )
      .run({
        zone_id: input.zoneId,
        home_id: input.homeId,
        name: input.name,
        type: input.type,
        created_at: createdAt,
      });

    const zone = this.getZoneById(input.zoneId);
    if (!zone) {
      throw new Error(`Failed to upsert zone ${input.zoneId}`);
    }

    return zone;
  }

  getZoneById(zoneId: string): HomeNodeZone | null {
    const row = this.db
      .prepare('SELECT zone_id, home_id, name, type FROM zones WHERE zone_id = ? LIMIT 1')
      .get(zoneId) as HomeNodeZoneRow | undefined;

    if (!row) {
      return null;
    }

    return toHomeNodeZone(row);
  }

  listZonesInHome(homeId: string): HomeNodeZone[] {
    const rows = this.db
      .prepare('SELECT zone_id, home_id, name, type FROM zones WHERE home_id = ? ORDER BY name ASC')
      .all(homeId) as HomeNodeZoneRow[];

    return rows.map((row) => toHomeNodeZone(row));
  }

  registerSurface(input: SurfaceRegistrationWrite): HomeNodeSurfaceRegistered {
    const home = this.getHomeById(input.homeId);
    if (!home) {
      throw new Error(
        `Cannot register surface ${input.surfaceId}: home ${input.homeId} was not found`,
      );
    }

    const zone = this.getZoneById(input.zoneId);
    if (!zone) {
      throw new Error(
        `Cannot register surface ${input.surfaceId}: zone ${input.zoneId} was not found`,
      );
    }

    if (zone.home_id !== input.homeId) {
      throw new Error(
        `Cannot register surface ${input.surfaceId}: zone ${input.zoneId} does not belong to home ${input.homeId}`,
      );
    }

    const existingSurface = this.db
      .prepare('SELECT trust_level FROM surfaces WHERE surface_id = ? LIMIT 1')
      .get(input.surfaceId) as { trust_level: SurfaceTrustLevel } | undefined;
    if (existingSurface && existingSurface.trust_level !== input.trustLevel) {
      throw new Error(
        `Cannot register surface ${input.surfaceId}: trust level is immutable once registered`,
      );
    }

    const registeredAt = ensureIsoDateTime(input.registeredAt ?? new Date().toISOString());
    const lastSeenAt = ensureIsoDateTime(input.lastSeenAt ?? registeredAt);

    this.db
      .prepare(
        `INSERT INTO surfaces (
          surface_id,
          zone_id,
          home_id,
          kind,
          trust_level,
          capabilities_json,
          active,
          registered_at,
          last_seen_at
        ) VALUES (
          @surface_id,
          @zone_id,
          @home_id,
          @kind,
          @trust_level,
          @capabilities_json,
          1,
          @registered_at,
          @last_seen_at
        )
        ON CONFLICT(surface_id) DO UPDATE SET
          zone_id = excluded.zone_id,
          home_id = excluded.home_id,
          kind = excluded.kind,
          capabilities_json = excluded.capabilities_json,
          active = 1,
          registered_at = excluded.registered_at,
          last_seen_at = excluded.last_seen_at`,
      )
      .run({
        surface_id: input.surfaceId,
        zone_id: input.zoneId,
        home_id: input.homeId,
        kind: input.kind,
        trust_level: input.trustLevel,
        capabilities_json: JSON.stringify(input.capabilities),
        registered_at: registeredAt,
        last_seen_at: lastSeenAt,
      });

    const row = this.getSurfaceRowWithHousehold(input.surfaceId);
    if (!row) {
      throw new Error(`Failed to register surface ${input.surfaceId}`);
    }

    return toHomeNodeSurfaceRegistered(row);
  }

  deregisterSurface(surfaceId: string): HomeNodeSurfaceRegistered | null {
    const row = this.getSurfaceRowWithHousehold(surfaceId);
    if (!row) {
      return null;
    }

    this.db.prepare('UPDATE surfaces SET active = 0 WHERE surface_id = ?').run(surfaceId);
    return toHomeNodeSurfaceRegistered(row);
  }

  getSurface(surfaceId: string): HomeNodeSurface | null {
    const row = this.db
      .prepare('SELECT * FROM surfaces WHERE surface_id = ? LIMIT 1')
      .get(surfaceId) as HomeNodeSurfaceRow | undefined;

    if (!row) {
      return null;
    }

    return toHomeNodeSurface(row);
  }

  getRegisteredSurface(surfaceId: string): HomeNodeSurfaceRegistered | null {
    const row = this.getSurfaceRowWithHousehold(surfaceId);
    if (!row) {
      return null;
    }

    return toHomeNodeSurfaceRegistered(row);
  }

  listSurfaces(filter: SurfaceListFilter = {}): HomeNodeSurface[] {
    const clauses: string[] = [];
    const params: unknown[] = [];

    if (filter.householdId) {
      clauses.push('h.household_id = ?');
      params.push(filter.householdId);
    }

    if (filter.homeId) {
      clauses.push('s.home_id = ?');
      params.push(filter.homeId);
    }

    if (filter.zoneId) {
      clauses.push('s.zone_id = ?');
      params.push(filter.zoneId);
    }

    if (filter.active !== undefined) {
      clauses.push('s.active = ?');
      params.push(filter.active ? 1 : 0);
    }

    const whereClause = clauses.length > 0 ? `WHERE ${clauses.join(' AND ')}` : '';
    const rows = this.db
      .prepare(
        `SELECT s.*
         FROM surfaces s
         INNER JOIN homes h ON h.home_id = s.home_id
         ${whereClause}
         ORDER BY s.registered_at DESC`,
      )
      .all(...params) as HomeNodeSurfaceRow[];

    return rows.map((row) => toHomeNodeSurface(row));
  }

  recordSurfaceHeartbeat(
    surfaceId: string,
    seenAt: string = new Date().toISOString(),
  ): HomeNodeSurface | null {
    const heartbeatAt = ensureIsoDateTime(seenAt);
    const row = this.db
      .prepare('SELECT 1 as present FROM surfaces WHERE surface_id = ? LIMIT 1')
      .get(surfaceId) as { present: number } | undefined;

    if (!row) {
      return null;
    }

    this.db
      .prepare('UPDATE surfaces SET active = 1, last_seen_at = ? WHERE surface_id = ?')
      .run(heartbeatAt, surfaceId);

    return this.getSurface(surfaceId);
  }

  listStaleActiveSurfaces(cutoff: string): HomeNodeSurfaceRegistered[] {
    const cutoffIso = ensureIsoDateTime(cutoff);
    const rows = this.db
      .prepare(
        `SELECT s.*, h.household_id
         FROM surfaces s
         INNER JOIN homes h ON h.home_id = s.home_id
         WHERE s.active = 1
           AND COALESCE(s.last_seen_at, s.registered_at) < ?
         ORDER BY COALESCE(s.last_seen_at, s.registered_at) ASC`,
      )
      .all(cutoffIso) as HomeNodeSurfaceWithHouseholdRow[];

    return rows.map((row) => toHomeNodeSurfaceRegistered(row));
  }

  markSurfaceInactive(surfaceId: string): boolean {
    const result = this.db
      .prepare('UPDATE surfaces SET active = 0 WHERE surface_id = ? AND active = 1')
      .run(surfaceId);

    return result.changes > 0;
  }

  private getSurfaceRowWithHousehold(surfaceId: string): HomeNodeSurfaceWithHouseholdRow | null {
    const row = this.db
      .prepare(
        `SELECT s.*, h.household_id
         FROM surfaces s
         INNER JOIN homes h ON h.home_id = s.home_id
         WHERE s.surface_id = ?
         LIMIT 1`,
      )
      .get(surfaceId) as HomeNodeSurfaceWithHouseholdRow | undefined;

    return row ?? null;
  }

  upsertHomeStateSnapshot(input: HomeStateSnapshotWrite): HomeStateSnapshot {
    const now = ensureIsoDateTime(input.snapshotAt ?? new Date().toISOString());
    const snapshot = HomeStateSnapshotSchema.parse({
      home_mode: input.homeMode,
      occupancy_summary: input.occupancySummary,
      active_routines: input.activeRoutines,
      adapter_health: input.adapterHealth,
      snapshot_at: now,
    });

    this.db
      .prepare(
        `INSERT INTO home_state_snapshots (
          id,
          household_id,
          home_mode,
          occupancy_summary_json,
          active_routines_json,
          adapter_health_json,
          snapshot_at,
          updated_at
        ) VALUES (
          @id,
          @household_id,
          @home_mode,
          @occupancy_summary_json,
          @active_routines_json,
          @adapter_health_json,
          @snapshot_at,
          @updated_at
        )
        ON CONFLICT(household_id) DO UPDATE SET
          home_mode = excluded.home_mode,
          occupancy_summary_json = excluded.occupancy_summary_json,
          active_routines_json = excluded.active_routines_json,
          adapter_health_json = excluded.adapter_health_json,
          snapshot_at = excluded.snapshot_at,
          updated_at = excluded.updated_at`,
      )
      .run({
        id: randomUUID(),
        household_id: input.householdId,
        home_mode: snapshot.home_mode,
        occupancy_summary_json: JSON.stringify(snapshot.occupancy_summary),
        active_routines_json: JSON.stringify(snapshot.active_routines),
        adapter_health_json: JSON.stringify({ status: snapshot.adapter_health }),
        snapshot_at: snapshot.snapshot_at,
        updated_at: now,
      });

    return snapshot;
  }

  getHomeStateSnapshot(householdId: string): HomeStateSnapshot | null {
    const row = this.db
      .prepare('SELECT * FROM home_state_snapshots WHERE household_id = ? LIMIT 1')
      .get(householdId) as HomeStateSnapshotRow | undefined;

    if (!row) {
      return null;
    }

    const occupancySummary = parseJson<string>(
      row.occupancy_summary_json,
      row.occupancy_summary_json,
    );
    const activeRoutines = parseJson<string[]>(row.active_routines_json, []);
    const adapterHealthRaw = parseJson<{ status?: string }>(row.adapter_health_json, {});

    return HomeStateSnapshotSchema.parse({
      home_mode: row.home_mode,
      occupancy_summary: occupancySummary,
      active_routines: activeRoutines,
      adapter_health:
        adapterHealthRaw.status === 'healthy' ||
        adapterHealthRaw.status === 'degraded' ||
        adapterHealthRaw.status === 'unavailable'
          ? adapterHealthRaw.status
          : 'healthy',
      snapshot_at: row.snapshot_at,
    });
  }

  appendAmbientAction(input: AmbientActionWrite): string {
    const actionId = randomUUID();
    const createdAt = ensureIsoDateTime(input.createdAt ?? new Date().toISOString());

    this.db
      .prepare(
        `INSERT INTO ambient_actions (
          action_id,
          household_id,
          trigger_type,
          trigger_ref,
          decision_source,
          affected_user_ids_json,
          output_surface_id,
          result,
          audit_ref,
          created_at
        ) VALUES (
          @action_id,
          @household_id,
          @trigger_type,
          @trigger_ref,
          @decision_source,
          @affected_user_ids_json,
          @output_surface_id,
          @result,
          @audit_ref,
          @created_at
        )`,
      )
      .run({
        action_id: actionId,
        household_id: input.householdId,
        trigger_type: input.triggerType,
        trigger_ref: input.triggerRef ?? null,
        decision_source: input.decisionSource,
        affected_user_ids_json: JSON.stringify(input.affectedUserIds ?? []),
        output_surface_id: input.outputSurfaceId ?? null,
        result: input.result,
        audit_ref: input.auditRef ?? null,
        created_at: createdAt,
      });

    return actionId;
  }

  getSnapshotRowCount(householdId: string): number {
    const row = this.db
      .prepare('SELECT COUNT(*) as count FROM home_state_snapshots WHERE household_id = ?')
      .get(householdId) as { count: number };

    return row.count;
  }

  isHealthy(): boolean {
    try {
      this.db.prepare('SELECT 1').get();
      return true;
    } catch {
      return false;
    }
  }

  close(): void {
    this.db.close();
  }
}

import { randomUUID } from 'node:crypto';

import {
  HomeNodeVoiceSessionCompletedSchema,
  HomeNodeVoiceSessionFailedSchema,
  HomeNodeVoiceSessionStartedSchema,
  HouseholdVoiceCaptureCreatedSchema,
  type HomeNodeVoiceSessionCompleted,
  type HomeNodeVoiceSessionFailed,
  type HomeNodeVoiceSessionStarted,
  type HouseholdVoiceCaptureCreated,
} from '@lifeos/contracts';
import { Topics, type BaseEvent, type ManagedEventBus } from '@lifeos/event-bus';
import type { AudioTranscriptionAdapter } from '@lifeos/voice-core';

const DEFAULT_SESSION_TTL_MS = 60_000;

export type VoiceSessionFailureReason =
  | 'quiet_hours'
  | 'transcription_failed'
  | 'empty_transcript'
  | 'expired';

export type VoiceSessionStatus = 'started' | 'completed' | 'failed' | 'closed';

export interface VoiceSessionRecord {
  sessionId: string;
  householdId: string;
  surfaceId: string;
  actorUserId: string;
  createdAt: string;
  updatedAt: string;
  expiresAt: string;
  status: VoiceSessionStatus;
  transcript?: string;
  targetHint?: HouseholdVoiceCaptureCreated['targetHint'];
  captureId?: string;
  audioRef?: string | null;
  failureReason?: VoiceSessionFailureReason;
  failureDetail?: string;
}

export interface VoiceSessionManagerOptions {
  eventBus: ManagedEventBus;
  transcriptionAdapter: AudioTranscriptionAdapter;
  now?: () => Date;
  idFactory?: () => string;
  sessionTtlMs?: number;
  retainAudio?: boolean;
}

export interface StartVoiceSessionInput {
  householdId: string;
  surfaceId: string;
  actorUserId: string;
  audioBuffer: Buffer;
  quietHoursActive: boolean;
}

export type StartVoiceSessionResult =
  | {
      status: 'completed';
      session: VoiceSessionRecord;
      capture: HouseholdVoiceCaptureCreated;
    }
  | {
      status: 'failed';
      session: VoiceSessionRecord;
      reason: VoiceSessionFailureReason;
    };

function cloneSession(session: VoiceSessionRecord): VoiceSessionRecord {
  return { ...session };
}

function isSessionActive(status: VoiceSessionStatus): boolean {
  return status === 'started';
}

function deriveTargetHint(text: string): HouseholdVoiceCaptureCreated['targetHint'] {
  const normalized = text.trim().toLowerCase();
  if (!normalized) {
    return 'unknown';
  }

  if (/(\bshopping\b|\bbuy\b|\bpick up\b|\bgrocer(?:y|ies)\b|\bstore\b)/.test(normalized)) {
    return 'shopping';
  }

  if (/(\bchore\b|\bclean\b|\btidy\b|\bvacuum\b|\bdishes\b|\blaundry\b)/.test(normalized)) {
    return 'chore';
  }

  if (/(\bremind\b|\breminder\b|\bremember\b|\bdon't forget\b|\bdont forget\b)/.test(normalized)) {
    return 'reminder';
  }

  if (/(\bnote\b|\bjot\b|\bwrite down\b|\bcapture\b)/.test(normalized)) {
    return 'note';
  }

  return 'unknown';
}

export class VoiceSessionManager {
  private readonly sessions = new Map<string, VoiceSessionRecord>();
  private readonly retainedAudio = new Map<string, Buffer>();
  private readonly eventBus: ManagedEventBus;
  private readonly transcriptionAdapter: AudioTranscriptionAdapter;
  private readonly now: () => Date;
  private readonly idFactory: () => string;
  private readonly sessionTtlMs: number;
  private readonly retainAudio: boolean;

  constructor(options: VoiceSessionManagerOptions) {
    this.eventBus = options.eventBus;
    this.transcriptionAdapter = options.transcriptionAdapter;
    this.now = options.now ?? (() => new Date());
    this.idFactory = options.idFactory ?? randomUUID;
    this.sessionTtlMs = options.sessionTtlMs ?? DEFAULT_SESSION_TTL_MS;
    this.retainAudio = options.retainAudio ?? false;
  }

  getSession(sessionId: string): VoiceSessionRecord | null {
    const session = this.sessions.get(sessionId);
    return session ? cloneSession(session) : null;
  }

  listSessions(): VoiceSessionRecord[] {
    return [...this.sessions.values()].map((session) => cloneSession(session));
  }

  async startSession(input: StartVoiceSessionInput): Promise<StartVoiceSessionResult> {
    const createdAt = this.now().toISOString();
    const sessionId = this.idFactory();
    const session: VoiceSessionRecord = {
      sessionId,
      householdId: input.householdId,
      surfaceId: input.surfaceId,
      actorUserId: input.actorUserId,
      createdAt,
      updatedAt: createdAt,
      expiresAt: new Date(new Date(createdAt).getTime() + this.sessionTtlMs).toISOString(),
      status: 'started',
    };
    this.sessions.set(sessionId, session);

    await this.publishStarted(session);

    if (input.quietHoursActive) {
      const failedSession = await this.markFailed(
        session,
        'quiet_hours',
        'Voice capture blocked during quiet hours.',
      );
      return { status: 'failed', session: failedSession, reason: 'quiet_hours' };
    }

    try {
      const transcript = (await this.transcriptionAdapter.transcribe(input.audioBuffer)).trim();

      // Session may have been expired while transcription was in flight.
      if (!isSessionActive(session.status)) {
        return {
          status: 'failed',
          session: cloneSession(session),
          reason: session.failureReason ?? 'expired',
        };
      }

      if (!transcript) {
        const failedSession = await this.markFailed(
          session,
          'empty_transcript',
          'Whisper produced an empty transcript.',
        );
        return { status: 'failed', session: failedSession, reason: 'empty_transcript' };
      }

      const audioRef = this.retainAudio ? this.retainSessionAudio(session.sessionId, input.audioBuffer) : null;
      const targetHint = deriveTargetHint(transcript);
      const capture = HouseholdVoiceCaptureCreatedSchema.parse({
        captureId: this.idFactory(),
        householdId: input.householdId,
        actorUserId: input.actorUserId,
        text: transcript,
        audioRef,
        source: 'ha_satellite',
        sourceDeviceId: input.surfaceId,
        targetHint,
        createdAt: this.now().toISOString(),
      });

      await this.eventBus.publish(
        Topics.lifeos.householdVoiceCaptureCreated,
        this.createEvent(
          Topics.lifeos.householdVoiceCaptureCreated,
          capture,
          input.householdId,
          input.surfaceId,
        ),
      );

      session.status = 'completed';
      session.updatedAt = this.now().toISOString();
      session.transcript = transcript;
      session.targetHint = targetHint;
      session.captureId = capture.captureId;
      session.audioRef = capture.audioRef;

      await this.publishCompleted(session, capture);
      return { status: 'completed', session: cloneSession(session), capture };
    } catch (error) {
      if (!isSessionActive(session.status)) {
        return {
          status: 'failed',
          session: cloneSession(session),
          reason: session.failureReason ?? 'expired',
        };
      }

      const failedSession = await this.markFailed(
        session,
        'transcription_failed',
        error instanceof Error ? error.message : 'Voice transcription failed.',
      );
      return { status: 'failed', session: failedSession, reason: 'transcription_failed' };
    }
  }

  async expireSessions(now: Date = this.now()): Promise<string[]> {
    const expiredIds: string[] = [];
    for (const session of this.sessions.values()) {
      if (!isSessionActive(session.status)) {
        continue;
      }

      if (new Date(session.expiresAt).getTime() > now.getTime()) {
        continue;
      }

      await this.markFailed(session, 'expired', 'Voice session expired before completion.');
      expiredIds.push(session.sessionId);
    }

    return expiredIds;
  }

  closeSession(sessionId: string): VoiceSessionRecord | null {
    const session = this.sessions.get(sessionId);
    if (!session) {
      return null;
    }

    session.status = 'closed';
    session.updatedAt = this.now().toISOString();
    this.retainedAudio.delete(sessionId);
    return cloneSession(session);
  }

  private retainSessionAudio(sessionId: string, audioBuffer: Buffer): string {
    this.retainedAudio.set(sessionId, Buffer.from(audioBuffer));
    return `memory://home-node-voice/${sessionId}`;
  }

  private async publishStarted(session: VoiceSessionRecord): Promise<void> {
    const payload: HomeNodeVoiceSessionStarted = HomeNodeVoiceSessionStartedSchema.parse({
      session_id: session.sessionId,
      household_id: session.householdId,
      surface_id: session.surfaceId,
      started_at: session.createdAt,
    });
    await this.eventBus.publish(
      Topics.lifeos.homeNodeVoiceSessionStarted,
      this.createEvent(
        Topics.lifeos.homeNodeVoiceSessionStarted,
        payload,
        session.householdId,
        session.surfaceId,
      ),
    );
  }

  private async publishCompleted(
    session: VoiceSessionRecord,
    capture: HouseholdVoiceCaptureCreated,
  ): Promise<void> {
    const payload: HomeNodeVoiceSessionCompleted = HomeNodeVoiceSessionCompletedSchema.parse({
      session_id: session.sessionId,
      household_id: session.householdId,
      surface_id: session.surfaceId,
      capture_id: capture.captureId,
      transcript: capture.text,
      target_hint: capture.targetHint,
      completed_at: session.updatedAt,
    });
    await this.eventBus.publish(
      Topics.lifeos.homeNodeVoiceSessionCompleted,
      this.createEvent(
        Topics.lifeos.homeNodeVoiceSessionCompleted,
        payload,
        session.householdId,
        session.surfaceId,
      ),
    );
  }

  private async markFailed(
    session: VoiceSessionRecord,
    reason: VoiceSessionFailureReason,
    detail: string,
  ): Promise<VoiceSessionRecord> {
    session.status = 'failed';
    session.updatedAt = this.now().toISOString();
    session.failureReason = reason;
    session.failureDetail = detail;

    const payload: HomeNodeVoiceSessionFailed = HomeNodeVoiceSessionFailedSchema.parse({
      session_id: session.sessionId,
      household_id: session.householdId,
      surface_id: session.surfaceId,
      reason,
      detail,
      failed_at: session.updatedAt,
    });
    await this.eventBus.publish(
      Topics.lifeos.homeNodeVoiceSessionFailed,
      this.createEvent(
        Topics.lifeos.homeNodeVoiceSessionFailed,
        payload,
        session.householdId,
        session.surfaceId,
      ),
    );

    return cloneSession(session);
  }

  private createEvent<T>(type: string, data: T, householdId: string, actorId: string): BaseEvent<T> {
    return {
      id: this.idFactory(),
      type,
      timestamp: this.now().toISOString(),
      source: 'home-node-voice-session-manager',
      version: '1',
      data,
      metadata: {
        household_id: householdId,
        actor_id: actorId,
        trace_id: this.idFactory(),
      },
    };
  }
}

import type { FastifyRequest } from 'fastify';

import { createSecurityClient, type AuthContext } from '@lifeos/security';

const securityClient = createSecurityClient();

function extractBearerToken(authorizationHeader: string | undefined): string | null {
  if (!authorizationHeader) {
    return null;
  }

  const token = authorizationHeader.startsWith('Bearer ')
    ? authorizationHeader.slice('Bearer '.length).trim()
    : authorizationHeader.trim();

  return token || null;
}

export async function extractAuthContext(request: FastifyRequest): Promise<AuthContext | null> {
  const token = extractBearerToken(request.headers.authorization);
  if (!token) {
    return null;
  }

  return securityClient.getAuthContext(token);
}

export async function extractCallerUserId(request: FastifyRequest): Promise<string | null> {
  const authContext = await extractAuthContext(request);
  if (!authContext || !authContext.subject) {
    return null;
  }

  return authContext.subject.trim() || null;
}

/**
 * RegExp to match cookie-name in RFC 6265 sec 4.1.1
 * This refers out to the obsoleted definition of token in RFC 2616 sec 2.2
 * which has been replaced by the token definition in RFC 7230 appendix B.
 *
 * cookie-name       = token
 * token             = 1*tchar
 * tchar             = "!" / "#" / "$" / "%" / "&" / "'" /
 *                     "*" / "+" / "-" / "." / "^" / "_" /
 *                     "`" / "|" / "~" / DIGIT / ALPHA
 *
 * Note: Allowing more characters - https://github.com/jshttp/cookie/issues/191
 * Allow same range as cookie value, except `=`, which delimits end of name.
 */
const cookieNameRegExp = /^[\u0021-\u003A\u003C\u003E-\u007E]+$/;

/**
 * RegExp to match cookie-value in RFC 6265 sec 4.1.1
 *
 * cookie-value      = *cookie-octet / ( DQUOTE *cookie-octet DQUOTE )
 * cookie-octet      = %x21 / %x23-2B / %x2D-3A / %x3C-5B / %x5D-7E
 *                     ; US-ASCII characters excluding CTLs,
 *                     ; whitespace DQUOTE, comma, semicolon,
 *                     ; and backslash
 *
 * Allowing more characters: https://github.com/jshttp/cookie/issues/191
 * Comma, backslash, and DQUOTE are not part of the parsing algorithm.
 */
const cookieValueRegExp = /^[\u0021-\u003A\u003C-\u007E]*$/;

/**
 * RegExp to match domain-value in RFC 6265 sec 4.1.1
 *
 * domain-value      = <subdomain>
 *                     ; defined in [RFC1034], Section 3.5, as
 *                     ; enhanced by [RFC1123], Section 2.1
 * <subdomain>       = <label> | <subdomain> "." <label>
 * <label>           = <let-dig> [ [ <ldh-str> ] <let-dig> ]
 *                     Labels must be 63 characters or less.
 *                     'let-dig' not 'letter' in the first char, per RFC1123
 * <ldh-str>         = <let-dig-hyp> | <let-dig-hyp> <ldh-str>
 * <let-dig-hyp>     = <let-dig> | "-"
 * <let-dig>         = <letter> | <digit>
 * <letter>          = any one of the 52 alphabetic characters A through Z in
 *                     upper case and a through z in lower case
 * <digit>           = any one of the ten digits 0 through 9
 *
 * Keep support for leading dot: https://github.com/jshttp/cookie/issues/173
 *
 * > (Note that a leading %x2E ("."), if present, is ignored even though that
 * character is not permitted, but a trailing %x2E ("."), if present, will
 * cause the user agent to ignore the attribute.)
 */
const domainValueRegExp =
  /^([.]?[a-z0-9]([a-z0-9-]{0,61}[a-z0-9])?)([.][a-z0-9]([a-z0-9-]{0,61}[a-z0-9])?)*$/i;

/**
 * RegExp to match path-value in RFC 6265 sec 4.1.1
 *
 * path-value        = <any CHAR except CTLs or ";">
 * CHAR              = %x01-7F
 *                     ; defined in RFC 5234 appendix B.1
 */
const pathValueRegExp = /^[\u0020-\u003A\u003D-\u007E]*$/;

/**
 * RegExp to match max-age-value in RFC 6265 sec 5.6.2
 */
const maxAgeRegExp = /^-?\d+$/;

const __toString = Object.prototype.toString;

const NullObject = /* @__PURE__ */ (() => {
  const C = function () {};
  C.prototype = Object.create(null);
  return C;
})() as unknown as { new (): any };

/**
 * Parse options.
 */
export interface ParseOptions {
  /**
   * Specifies a function that will be used to decode a [cookie-value](https://datatracker.ietf.org/doc/html/rfc6265#section-4.1.1).
   * Since the value of a cookie has a limited character set (and must be a simple string), this function can be used to decode
   * a previously-encoded cookie value into a JavaScript string.
   *
   * The default function is the global `decodeURIComponent`, wrapped in a `try..catch`. If an error
   * is thrown it will return the cookie's original value. If you provide your own encode/decode
   * scheme you must ensure errors are appropriately handled.
   *
   * @default decode
   */
  decode?: (str: string) => string | undefined;
}

/**
 * Cookies object.
 */
export type Cookies = Record<string, string | undefined>;

/**
 * Parse a `Cookie` header.
 *
 * Parse the given cookie header string into an object
 * The object has the various cookies as keys(names) => values
 */
export function parseCookie(str: string, options?: ParseOptions): Cookies {
  const obj: Cookies = new NullObject();
  const len = str.length;
  // RFC 6265 sec 4.1.1, RFC 2616 2.2 defines a cookie name consists of one char minimum, plus '='.
  if (len < 2) return obj;

  const dec = options?.decode || decode;
  let index = 0;

  do {
    const eqIdx = eqIndex(str, index, len);
    if (eqIdx === -1) break; // No more cookie pairs.

    const endIdx = endIndex(str, index, len);

    if (eqIdx > endIdx) {
      // backtrack on prior semicolon
      index = str.lastIndexOf(";", eqIdx - 1) + 1;
      continue;
    }

    const key = valueSlice(str, index, eqIdx);

    // only assign once
    if (obj[key] === undefined) {
      obj[key] = dec(valueSlice(str, eqIdx + 1, endIdx));
    }

    index = endIdx + 1;
  } while (index < len);

  return obj;
}

export interface StringifyOptions {
  /**
   * Specifies a function that will be used to encode a [cookie-value](https://datatracker.ietf.org/doc/html/rfc6265#section-4.1.1).
   * Since value of a cookie has a limited character set (and must be a simple string), this function can be used to encode
   * a value into a string suited for a cookie's value, and should mirror `decode` when parsing.
   *
   * @default encodeURIComponent
   */
  encode?: (str: string) => string;
}

/**
 * Stringifies an object into an HTTP `Cookie` header.
 */
export function stringifyCookie(
  cookie: Cookies,
  options?: StringifyOptions,
): string {
  const enc = options?.encode || encodeURIComponent;
  const cookieStrings: string[] = [];

  for (const name of Object.keys(cookie)) {
    const val = cookie[name];
    if (val === undefined) continue;

    if (!cookieNameRegExp.test(name)) {
      throw new TypeError(`cookie name is invalid: ${name}`);
    }

    const value = enc(val);

    if (!cookieValueRegExp.test(value)) {
      throw new TypeError(`cookie val is invalid: ${val}`);
    }

    cookieStrings.push(`${name}=${value}`);
  }

  return cookieStrings.join("; ");
}

/**
 * Set-Cookie object.
 */
export interface SetCookie {
  /**
   * Specifies the name of the cookie.
   */
  name: string;
  /**
   * Specifies the string to be the value for the cookie.
   */
  value: string | undefined;
  /**
   * Specifies the `number` (in seconds) to be the value for the [`Max-Age` `Set-Cookie` attribute](https://tools.ietf.org/html/rfc6265#section-5.2.2).
   *
   * The [cookie storage model specification](https://tools.ietf.org/html/rfc6265#section-5.3) states that if both `expires` and
   * `maxAge` are set, then `maxAge` takes precedence, but it is possible not all clients by obey this,
   * so if both are set, they should point to the same date and time.
   */
  maxAge?: number;
  /**
   * Specifies the `Date` object to be the value for the [`Expires` `Set-Cookie` attribute](https://tools.ietf.org/html/rfc6265#section-5.2.1).
   * When no expiration is set, clients consider this a "non-persistent cookie" and delete it when the current session is over.
   *
   * The [cookie storage model specification](https://tools.ietf.org/html/rfc6265#section-5.3) states that if both `expires` and
   * `maxAge` are set, then `maxAge` takes precedence, but it is possible not all clients by obey this,
   * so if both are set, they should point to the same date and time.
   */
  expires?: Date;
  /**
   * Specifies the value for the [`Domain` `Set-Cookie` attribute](https://tools.ietf.org/html/rfc6265#section-5.2.3).
   * When no domain is set, clients consider the cookie to apply to the current domain only.
   */
  domain?: string;
  /**
   * Specifies the value for the [`Path` `Set-Cookie` attribute](https://tools.ietf.org/html/rfc6265#section-5.2.4).
   * When no path is set, the path is considered the ["default path"](https://tools.ietf.org/html/rfc6265#section-5.1.4).
   */
  path?: string;
  /**
   * Enables the [`HttpOnly` `Set-Cookie` attribute](https://tools.ietf.org/html/rfc6265#section-5.2.6).
   * When enabled, clients will not allow client-side JavaScript to see the cookie in `document.cookie`.
   */
  httpOnly?: boolean;
  /**
   * Enables the [`Secure` `Set-Cookie` attribute](https://tools.ietf.org/html/rfc6265#section-5.2.5).
   * When enabled, clients will only send the cookie back if the browser has an HTTPS connection.
   */
  secure?: boolean;
  /**
   * Enables the [`Partitioned` `Set-Cookie` attribute](https://tools.ietf.org/html/draft-cutler-httpbis-partitioned-cookies/).
   * When enabled, clients will only send the cookie back when the current domain _and_ top-level domain matches.
   *
   * This is an attribute that has not yet been fully standardized, and may change in the future.
   * This also means clients may ignore this attribute until they understand it. More information
   * about can be found in [the proposal](https://github.com/privacycg/CHIPS).
   */
  partitioned?: boolean;
  /**
   * Specifies the value for the [`Priority` `Set-Cookie` attribute](https://tools.ietf.org/html/draft-west-cookie-priority-00#section-4.1).
   *
   * - `'low'` will set the `Priority` attribute to `Low`.
   * - `'medium'` will set the `Priority` attribute to `Medium`, the default priority when not set.
   * - `'high'` will set the `Priority` attribute to `High`.
   *
   * More information about priority levels can be found in [the specification](https://tools.ietf.org/html/draft-west-cookie-priority-00#section-4.1).
   */
  priority?: "low" | "medium" | "high";
  /**
   * Specifies the value for the [`SameSite` `Set-Cookie` attribute](https://tools.ietf.org/html/draft-ietf-httpbis-rfc6265bis-09#section-5.4.7).
   *
   * - `true` will set the `SameSite` attribute to `Strict` for strict same site enforcement.
   * - `'lax'` will set the `SameSite` attribute to `Lax` for lax same site enforcement.
   * - `'none'` will set the `SameSite` attribute to `None` for an explicit cross-site cookie.
   * - `'strict'` will set the `SameSite` attribute to `Strict` for strict same site enforcement.
   *
   * More information about enforcement levels can be found in [the specification](https://tools.ietf.org/html/draft-ietf-httpbis-rfc6265bis-09#section-5.4.7).
   */
  sameSite?: boolean | "lax" | "strict" | "none";
}

/**
 * Backward compatibility serialize options.
 */
export type SerializeOptions = StringifyOptions &
  Omit<SetCookie, "name" | "value">;

/**
 * Serialize data into a cookie header.
 *
 * Serialize a name value pair into a cookie string suitable for
 * http headers. An optional options object specifies cookie parameters.
 *
 * serialize('foo', 'bar', { httpOnly: true })
 *   => "foo=bar; httpOnly"
 */
export function stringifySetCookie(
  cookie: SetCookie,
  options?: StringifyOptions,
): string;
export function stringifySetCookie(
  name: string,
  val: string,
  options?: SerializeOptions,
): string;
export function stringifySetCookie(
  _name: string | SetCookie,
  _val?: string | StringifyOptions,
  _opts?: SerializeOptions,
): string {
  const cookie =
    typeof _name === "object"
      ? _name
      : { ..._opts, name: _name, value: String(_val) };
  const options = typeof _val === "object" ? _val : _opts;
  const enc = options?.encode || encodeURIComponent;

  if (!cookieNameRegExp.test(cookie.name)) {
    throw new TypeError(`argument name is invalid: ${cookie.name}`);
  }

  const value = cookie.value ? enc(cookie.value) : "";

  if (!cookieValueRegExp.test(value)) {
    throw new TypeError(`argument val is invalid: ${cookie.value}`);
  }

  let str = cookie.name + "=" + value;

  if (cookie.maxAge !== undefined) {
    if (!Number.isInteger(cookie.maxAge)) {
      throw new TypeError(`option maxAge is invalid: ${cookie.maxAge}`);
    }

    str += "; Max-Age=" + cookie.maxAge;
  }

  if (cookie.domain) {
    if (!domainValueRegExp.test(cookie.domain)) {
      throw new TypeError(`option domain is invalid: ${cookie.domain}`);
    }

    str += "; Domain=" + cookie.domain;
  }

  if (cookie.path) {
    if (!pathValueRegExp.test(cookie.path)) {
      throw new TypeError(`option path is invalid: ${cookie.path}`);
    }

    str += "; Path=" + cookie.path;
  }

  if (cookie.expires) {
    if (!isDate(cookie.expires) || !Number.isFinite(cookie.expires.valueOf())) {
      throw new TypeError(`option expires is invalid: ${cookie.expires}`);
    }

    str += "; Expires=" + cookie.expires.toUTCString();
  }

  if (cookie.httpOnly) {
    str += "; HttpOnly";
  }

  if (cookie.secure) {
    str += "; Secure";
  }

  if (cookie.partitioned) {
    str += "; Partitioned";
  }

  if (cookie.priority) {
    const priority =
      typeof cookie.priority === "string"
        ? cookie.priority.toLowerCase()
        : undefined;
    switch (priority) {
      case "low":
        str += "; Priority=Low";
        break;
      case "medium":
        str += "; Priority=Medium";
        break;
      case "high":
        str += "; Priority=High";
        break;
      default:
        throw new TypeError(`option priority is invalid: ${cookie.priority}`);
    }
  }

  if (cookie.sameSite) {
    const sameSite =
      typeof cookie.sameSite === "string"
        ? cookie.sameSite.toLowerCase()
        : cookie.sameSite;
    switch (sameSite) {
      case true:
      case "strict":
        str += "; SameSite=Strict";
        break;
      case "lax":
        str += "; SameSite=Lax";
        break;
      case "none":
        str += "; SameSite=None";
        break;
      default:
        throw new TypeError(`option sameSite is invalid: ${cookie.sameSite}`);
    }
  }

  return str;
}

/**
 * Deserialize a `Set-Cookie` header into an object.
 *
 * deserialize('foo=bar; httpOnly')
 *   => { name: 'foo', value: 'bar', httpOnly: true }
 */
export function parseSetCookie(str: string, options?: ParseOptions): SetCookie {
  const dec = options?.decode || decode;
  const len = str.length;
  const endIdx = endIndex(str, 0, len);
  const eqIdx = eqIndex(str, 0, endIdx);
  const setCookie: SetCookie =
    eqIdx === -1
      ? { name: "", value: dec(valueSlice(str, 0, endIdx)) }
      : {
          name: valueSlice(str, 0, eqIdx),
          value: dec(valueSlice(str, eqIdx + 1, endIdx)),
        };

  let index = endIdx + 1;
  while (index < len) {
    const endIdx = endIndex(str, index, len);
    const eqIdx = eqIndex(str, index, endIdx);
    const attr =
      eqIdx === -1
        ? valueSlice(str, index, endIdx)
        : valueSlice(str, index, eqIdx);
    const val = eqIdx === -1 ? undefined : valueSlice(str, eqIdx + 1, endIdx);

    switch (attr.toLowerCase()) {
      case "httponly":
        setCookie.httpOnly = true;
        break;
      case "secure":
        setCookie.secure = true;
        break;
      case "partitioned":
        setCookie.partitioned = true;
        break;
      case "domain":
        setCookie.domain = val;
        break;
      case "path":
        setCookie.path = val;
        break;
      case "max-age":
        if (val && maxAgeRegExp.test(val)) setCookie.maxAge = Number(val);
        break;
      case "expires":
        if (!val) break;
        const date = new Date(val);
        if (Number.isFinite(date.valueOf())) setCookie.expires = date;
        break;
      case "priority":
        if (!val) break;
        const priority = val.toLowerCase();
        if (
          priority === "low" ||
          priority === "medium" ||
          priority === "high"
        ) {
          setCookie.priority = priority;
        }
        break;
      case "samesite":
        if (!val) break;
        const sameSite = val.toLowerCase();
        if (
          sameSite === "lax" ||
          sameSite === "strict" ||
          sameSite === "none"
        ) {
          setCookie.sameSite = sameSite;
        }
        break;
    }

    index = endIdx + 1;
  }

  return setCookie;
}

/**
 * Find the `;` character between `min` and `len` in str.
 */
function endIndex(str: string, min: number, len: number) {
  const index = str.indexOf(";", min);
  return index === -1 ? len : index;
}

/**
 * Find the `=` character between `min` and `max` in str.
 */
function eqIndex(str: string, min: number, max: number) {
  const index = str.indexOf("=", min);
  return index < max ? index : -1;
}

/**
 * Slice out a value between startPod to max.
 */
function valueSlice(str: string, min: number, max: number) {
  let start = min;
  let end = max;

  do {
    const code = str.charCodeAt(start);
    if (code !== 0x20 /*   */ && code !== 0x09 /* \t */) break;
  } while (++start < end);

  while (end > start) {
    const code = str.charCodeAt(end - 1);
    if (code !== 0x20 /*   */ && code !== 0x09 /* \t */) break;
    end--;
  }

  return str.slice(start, end);
}

/**
 * URL-decode string value. Optimized to skip native call when no %.
 */
function decode(str: string): string {
  if (str.indexOf("%") === -1) return str;

  try {
    return decodeURIComponent(str);
  } catch (e) {
    return str;
  }
}

/**
 * Determine if value is a Date.
 */
function isDate(val: any): val is Date {
  return __toString.call(val) === "[object Date]";
}

/**
 * Backward compatibility exports.
 */
export { stringifySetCookie as serialize, parseCookie as parse };
